// Require input
    if (inputs.Length == 0 || inputs[0] == null)
    {
        return PixelBufferPool.Borrow(context.TileSize, context.TileSize);
    }

    var input = inputs[0]!;
    var size = context.TileSize;
    var fillColor = GetColor(parameters, "fillColor", Colors.Red);
    var tolerance = Math.Clamp(GetFloat(parameters, "tolerance", 0.1f), 0f, 1f);

    var fR = fillColor.R / 255f;
    var fG = fillColor.G / 255f;
    var fB = fillColor.B / 255f;

    // Determine seed position
    int seedX, seedY;

    if (inputs.Length > 1 && inputs[1] != null)
    {
        // For a single Float input, read the luminance-ish value (R channel) and map to position
        // We'll read the center pixel of the optional buffer and use its R and G channels as normalized coords.
        var (sr, sg, _, _) = inputs[1]!.GetPixel(0, 0);
        seedX = Math.Clamp((int)(sr * (size - 1)), 0, size - 1);
        seedY = Math.Clamp((int)(sg * (size - 1)), 0, size - 1);
    }
    else
    {
        // Default to center
        seedX = size / 2;
        seedY = size / 2;
    }

    var buffer = PixelBufferPool.Borrow(size, size);

    // Copy input to buffer
    buffer.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);
        buffer.SetPixel(x, y, r, g, b, a);
    });

    // Get the reference color at the seed point
    var (refR, refG, refB, refA) = buffer.GetPixel(seedX, seedY);

    // If seed color already matches (within tolerance), no fill needed
    if (ColorMatch(refR, refG, refB, fR, fG, fB, tolerance))
    {
        return buffer;
    }

    // Scanline flood fill (iterative, stack-based)
    var visited = new bool[size, size];
    var stack = new Stack<(int x, int y)>();
    stack.Push((seedX, seedY));

    while (stack.Count > 0)
    {
        var (cx, cy) = stack.Pop();
        if (cx < 0 || cx >= size || cy < 0 || cy >= size) continue;
        if (visited[cy, cx]) continue;

        var (cr, cg, cb, ca) = buffer.GetPixel(cx, cy);

        // Check if this pixel matches the reference color
        if (!ColorMatch(cr, cg, cb, refR, refG, refB, tolerance))
            continue;

        visited[cy, cx] = true;
        buffer.SetPixel(cx, cy, fR, fG, fB, 1f);

        stack.Push((cx - 1, cy));
        stack.Push((cx + 1, cy));
        stack.Push((cx, cy - 1));
        stack.Push((cx, cy + 1));
    }

    return buffer;

/// <summary>
/// Checks if two colors match within the given tolerance (Euclidean distance in RGB space).
/// </summary>
private static bool ColorMatch(float r1, float g1, float b1, float r2, float g2, float b2, float tolerance)
{
    var dr = r1 - r2;
    var dg = g1 - g2;
    var db = b1 - b2;
    var dist = MathF.Sqrt(dr * dr + dg * dg + db * db);
    // Maximum possible distance in RGB cube is sqrt(3) ~ 1.732
    return dist <= tolerance * 1.732f;
    }
